//stackedTotal.js

import { PERCENT_SHOWAS, PER_SHOWAS } from '../../label/showas-constants';
import { stack } from '../main-zc-init';
import { mathAbs } from '../zc-constants';
// import { getStackGroupIndex } from '../data-processor/transforms/stack/stack-grouping';

export const getStackedTotal = stack.getStackedTotal = function getStackedTotal(chartObj, seriesPos, d, showAs) {
    var stackGroupIdx = stack.getStackGroupIndex(chartObj.dataObject.getStackGroup(), seriesPos),
        rp = chartObj.renderer[seriesPos].commonRendererProp().params,
        dataset = chartObj.dataset,
        X = dataset.getX(d),
        Y = dataset.getY(d, rp.yaxiscolumnorder || 0),
        total;

    var curStackExtent = chartObj.dataObject
        .getEncode('stack', stackGroupIdx)
        .layout.getAllExtents()
        .filter(d => d[0] == X);

    if (showAs === PERCENT_SHOWAS || showAs === PER_SHOWAS) {
        total = curStackExtent.reduce(function (prev, cur) {
            return prev + mathAbs(cur[1]);
        }, 0);
    } else {
        total = curStackExtent[Y < rp.hasNegValue && curStackExtent[1] ? 1 : 0][1];
    }
    return total;
}
